const aiResult = $input.first().json.output || $input.first().json;
 const taskId = 'task_' + Date.now();

 // 如果 aiResult 是字符串就直接用，否则转字符串
 const text = typeof aiResult === 'string' ? aiResult : JSON.stringify(aiResult);

 return {
   json: {
     success: true,
     taskId: taskId,
     status: 'waiting_user_feedback',
     stepName: 'draft',
     message: '初稿已生成，请预览并确认或提出修改意见',
     preview: {
       text: text,
       images: [],
       videos: []
     },
     history: [
       { role: 'system', type: 'status', content: '✅ AI 已生成初稿', timestamp: Date.now() }
     ],
     allowRevise: true,
     allowConfirm: true
   }
 };

const aiText = $input.first().json.output || $input.first().json.text ||
  JSON.stringify($input.first().json);
  const action = $('codes').item.json.action;
  const taskId = $('codes').item.json.taskId;

  const isConfirm = action === 'confirm';

  return {
    json: {
      success: true,
      taskId: taskId,
      status: isConfirm ? 'completed' : 'waiting_user_feedback',
      stepName: isConfirm ? 'final' : 'draft',
      message: isConfirm ? '最终版已生成！' : '已根据修改意见重新生成，请再次确认',
      preview: {
        text: aiText,
        images: [],
        videos: []
      },
      history: [
        {
          role: 'system',
          type: 'status',
          content: isConfirm ? '最终版已生成' : '已根据修改意见重新生成',
          timestamp: Date.now()
        }
      ],
      allowRevise: isConfirm ? false : true,
      allowConfirm: isConfirm ? false : true
    }
  };

const body = $input.first().json.body;
  const action = body.action;
  const feedback = body.feedback;
  const previousText = body.previousText;
  const taskId = body.taskId;

  let prompt = '';

  if (action === 'revise') {
    if (previousText) {
      prompt = '以下是你之前生成的初稿：\n\n' + previousText + '\n\n用户提出了修改意见：' +        
  feedback + '\n\n请根据修改意见重新生成完整文案，保持原有格式和结构。';
    } else {
      prompt = '用户对你上一版的文案提出了新的修改意见：' + feedback +
  '\n\n请根据修改意见重新生成完整文案。';
    }
  } else {
    prompt = '用户已确认当前文案，请直接原样输出最终完整版文案，不做任何修改。';
  }

  return {
    json: {
      prompt: prompt,
      action: action,
      taskId: taskId,
      previousText: previousText || ''
    }
  };

const previousText = $('codes').item.json.previousText || '';
  const taskId = $('codes').item.json.taskId || '';

  // 清理 AI 多余的说明性文字，找到 [封面] 开始的正式内容
  var cleanText = previousText;
  var coverStart = cleanText.indexOf('[封面]');
  if (coverStart > 0) {
    cleanText = cleanText.substring(coverStart);
  }

  // 按 <page> 分割
  var sections = cleanText.split('<page>').map(function(s) { return s.trim(); }).filter(function(s) { return s; });

  // 解析每页类型
  var pages = sections.map(function(content, index) {
    var typeMatch = content.match(/^\[(\S+?)\]/);
    var typeMap = { '封面': 'cover', '内容': 'content', '总结': 'summary' };
    var type = typeMatch ? (typeMap[typeMatch[1]] || 'content') : 'content';
    return { index: index, type: type, content: content };
  });

  // 封面页
  var coverPage = null;
  for (var i = 0; i < pages.length; i++) {
    if (pages[i].type === 'cover') { coverPage = pages[i]; break; }
  }

  // 非封面页
  var otherPages = pages.filter(function(p) { return p.type !== 'cover'; });

  return {
    json: {
      taskId: taskId,
      previousText: previousText,
      outline: cleanText,
      userRequest: '根据文案内容生成配图',
      coverPage: coverPage,
      otherPages: otherPages,
      pageCount: pages.length
    }
  };

const outline = $('codes').first().json.outline;
  const userRequest = $('codes').first().json.userRequest;
    const coverImage = $('fm').first().json.imageUrl; // 改成实际字段名

  return $input.all().map(function(item) {
    return {
      json: {
        page: item.json,
        outline: outline,
        userRequest: userRequest,
        coverImage: coverImage
      }
    };
  });

var data = $input.first().json.data;
  var images = data.map(function(item) { return item.imageUrl; }).filter(function(url) { return url; });

  var previousText = $('codes').first().json.previousText || '';
  var taskId = $('codes').first().json.taskId || '';

  return {
    json: {
      success: true,
      taskId: taskId,
      status: 'completed',
      stepName: 'final',
      message: '最终文案和配图已生成！',
      preview: {
        text: previousText,
        images: images,
        videos: []
      },
      history: [
        {
          role: 'system',
          type: 'status',
          content: '最终版文案和配图已生成',
          timestamp: Date.now()
        }
      ],
      allowRevise: false,
      allowConfirm: false
    }
  };
